class Solution:
    def threeSum(self, nums: list[int]) -> list[list[int]]:
        
        # Base case
        if len(nums) < 3:
            return []

        if len(nums) == 3:
            if nums[0] + nums[1] + nums[2] == 0:
                return [[nums[0], nums[1], nums[2]]]
            else:   
                return []
            
        # All numbers in nums only 0
        temp = set(nums)
        if len(temp) == 1 and 0 in temp:
            return [0,0,0]
            
        # Other cases
        triplets = set()
        thedict = {}
        for index, num in enumerate(nums):
            if num not in thedict:
                thedict[num] = [index]

            else:
                thedict[num].append(index)

            
        front, back = 0, len(nums) - 1

        while front < len(nums):
            while back >= 0:
                num_to_search = 0 - (nums[front] + nums[back])
                if (num_to_search in thedict):
                    for index_of_value_in_dict in thedict.get(num_to_search):
                        if front != back and front != index_of_value_in_dict and back != index_of_value_in_dict:
                            triplets.add(tuple(sorted([nums[front], nums[back], nums[index_of_value_in_dict]])))

                back -= 1
            
            front += 1
            back = len(nums) - 1

        print(triplets)



